	const app = await NestFactory.create(ApiGatewayModule);

	const config = app.get(ConfigService);
	const port = config.get<number>('API_GATEWAY_SERVICE_PORT', 5001);

	app.setGlobalPrefix('api');
	app.enableCors();

	await app.listen(port);
}

	const appContext = await NestFactory.createApplicationContext(AuthServiceModule);
	const config = appContext.get(ConfigService);

	const port = config.get<number>('AUTH_SERVICE_PORT', 5002);

	await appContext.close();

	const app = await NestFactory.createMicroservice(AuthServiceModule, {
		transport: Transport.TCP,
		options: {
			host: '0.0.0.0',
			port
		}
	});

	await app.listen();
}

	const appContext = await NestFactory.createApplicationContext(ServiceAModule);
	const config = appContext.get(ConfigService);

	const port = config.get<number>('SERVICE_A_PORT', 5003);

	await appContext.close();

	const app = await NestFactory.createMicroservice(ServiceAModule, {
		transport: Transport.TCP,
		options: {
			host: '0.0.0.0',
			port
		}
	});

	await app.listen();
}

	const appContext = await NestFactory.createApplicationContext(ServiceBModule);
		const config = appContext.get(ConfigService);

		const port = config.get<number>('SERVICE_B_PORT', 5004);

		await appContext.close();

		const app = await NestFactory.createMicroservice(ServiceBModule, {
			transport: Transport.TCP,
			options: {
				host: '0.0.0.0',
				port
			}
		});

		await app.listen();
}
